import cadquery as cq

class BottomCircleSelector(cq.Selector):
    def filter(self, objectList):
        circles = []
        for o in objectList:
            try:
                if o.geomType() == "CIRCLE":
                    circles.append(o)
            except AttributeError:
                pass
        if circles:
            return [min(circles, key=lambda c: c.Center().z)]
        return []

class TopCircleSelector(cq.Selector):
    def filter(self, objectList):
        circles = []
        for o in objectList:
            try:
                if o.geomType() == "CIRCLE":
                    circles.append(o)
            except AttributeError:
                pass
        if circles:
            return [max(circles, key=lambda c: c.Center().z)]
        return []

